// 当 Mode 为 "Run Once for All Items" 时，输入是一个名为 $input.all() 的数组
const allItems = $input.all();

// 处理每一项数据（通常 Chat Trigger 只有 1 个 Item）
return allItems.map(item => {
  const newBinary = {};

  // 获取当前 item 中所有的二进制键名 (例如: data0, data1)
  const binaryKeys = Object.keys(item.binary || {});

  // 按照你的要求，提取前 3 张并重命名
  binaryKeys.slice(0, 3).forEach((key, index) => {
    newBinary[`image_${index}`] = item.binary[key];
  });

  // 返回符合 n8n 规范的结构
  return {
    json: item.json,
    binary: newBinary
  };
});

const items = $input.all();

// 辅助函数：清洗字符串
const toStr = (v) => (v == null ? '' : String(v).trim());

/**
 * 核心逻辑：跨节点提取上上上游的文字信息
 * 无论当前工作流经过了多少次拆分，
 * 只要 Code in JavaScript2 执行过，就能通过节点名称找回数据。
 */
const getPromptFromSource = () => {
  try {
    // 使用 $() 语法精准定位到“Code in JavaScript2”节点
    const sourceNode = $('Code in JavaScript2').first();

    // 根据你的截图，文字存放在 body.prompt 或者直接在 json.prompt 中
    // 这里做一层兼容性处理
    return toStr(sourceNode.json.prompt || sourceNode.json.body?.prompt);
  } catch (error) {
    // 如果找不到节点或字段，返回空字符串，避免整个工作流崩溃
    return "";
  }
};

const finalPrompt = getPromptFromSource();
const newBinary = {};

// 处理图片：将当前节点收到的 1~3 张二进制图重新打包
for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};

  // 筛选图片相关的 Key
  const keys = Object.keys(bin).filter(k =>
    k.startsWith('image') || k.startsWith('data') || k.startsWith('file') || k.startsWith('webp')
  );

  for (const key of keys) {
    // 重新编号：image_0, image_1...
    const newKey = `image_${i}`;
    newBinary[newKey] = bin[key];
  }
}

// 返回最终的对象数组格式
return [{
  json: {
    prompt: finalPrompt,      // 这就是你上上上游丢失的文字
    total_images: items.length
  },
  binary: newBinary          // 聚合后的图片数据
}];

const items = $input.all();

// 辅助函数：清洗与标准化
const toStr = (v) => (v == null ? '' : String(v));
const normalize = (s) => {
  let t = toStr(s);
  t = t.replace(/\r\n/g, '\n');
  if (t.includes('\\n')) t = t.replace(/\\n/g, '\n');
  return t.trim();
};

// 1. 获取源文本：精准锁定 Code in JavaScript3
const getSourceText = () => {
  try {
    const n = $('Code in JavaScript3').first();
    return normalize(n?.json?.prompt || '');
  } catch (_) {
    const j = items[0]?.json || {};
    return normalize(j.prompt || j.chatInput || '');
  }
};

// 2. 【核心优化】改进拆分正则
const splitByMarker = (s) => {
  // 使用更宽松的正则：不强制在行首，只要出现“屏幕定位”就切分
  // (?=屏幕定位) 是正向预查，保留关键词在段落开头
  const segments = s.split(/(?=屏幕定位[:：])/);

  // 清洗每一段，去掉长度过短的无效段落
  return segments
    .map(seg => seg.trim())
    .filter(seg => seg.length > 5);
};

// 3. 收集二进制数据：保留 1~3 张参考图
const collectSharedBinary = async () => {
  let bin = {};
  try {
    // 优先从上游聚合节点获取
    const n = $('Code in JavaScript3').first();
    bin = n?.binary || {};
  } catch (_) {
    bin = items[0]?.binary || {};
  }

  const out = {};
  for (const k of Object.keys(bin)) {
    // 强制克隆二进制引用，防止 n8n 引擎在输出多个 Item 时丢失数据
    const buf = await this.helpers.getBinaryDataBuffer(0, k);
    out[k] = await this.helpers.prepareBinaryData(buf, bin[k].fileName, bin[k].mimeType);
  }
  return out;
};

// 执行主逻辑
const text = getSourceText();
const segments = splitByMarker(text);
const sharedBinary = await collectSharedBinary();

// 4. 组装输出：一段文字 + 相同的三张图
const outputs = segments.map((seg, i) => {
  const item = { 
    json: { 
      index: i + 1, 
      Prompt: seg 
    } 
  };
  if (Object.keys(sharedBinary).length) {
    item.binary = sharedBinary;
  }
  return item;
});

return outputs.length ? outputs : [{ json: { index: 0, Prompt: '未检测到有效段落' } }];

const items = $input.all();
const outputs = [];

for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  const keys = Object.keys(bin);

  if (!keys.length) {
    outputs.push({ json: { key: '', fileName: '', mimeType: '', url: '' } });
    continue;
  }

  for (const key of keys) {
    const meta = bin[key] || {};
    let url = '';
    try {
      const buf = await this.helpers.getBinaryDataBuffer(i, key);
      const mime = meta.mimeType || meta.mimetype || 'application/octet-stream';
      const base64 = Buffer.isBuffer(buf) ? buf.toString('base64') : Buffer.from(buf).toString('base64');
      url = base64 ? `data:${mime};base64,${base64}` : '';
    } catch (_) {
      const mime = meta.mimeType || meta.mimetype || 'application/octet-stream';
      const data = meta.data;
      if (typeof data === 'string' && data.length) url = `data:${mime};base64,${data}`;
    }

    outputs.push({
      json: {
        key,
        fileName: meta.fileName || meta.filename || key,
        mimeType: meta.mimeType || meta.mimetype || '',
        url
      }
    });
  }
}

return outputs.length ? outputs : [{ json: { key: '', fileName: '', mimeType: '', url: '' } }];

